with seed_persons (code, name, tagline, avatar_url, description, is_active, era_codes) as (
  values
    ('god', '하나님', '출애굽 시대 인물', 'assets/avatars/god.png', '하나님은 세상을 창조하시고 역사를 주관하시는 분이다. 성경의 모든 이야기는 하나님의 뜻과 구원 계획 안에서 이어진다.', false, ARRAY['era_primeval', 'era_patriarch', 'era_exodus', 'era_judges', 'era_monarchy', 'era_divided_kingdom']::text[]),
    ('jesus', '예수님', '하나님의 아들', 'assets/avatars/jesus.png', '예수님은 하나님의 아들로, 사람들에게 하나님 나라를 가르치고 병든 자를 고치셨다. 십자가와 부활로 구원의 길을 여신 분이다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic', 'era_nt_post_apostolic', 'era_nt_consummation']::text[]),
    ('paul', '바울', '이방인을 위한 사도', 'assets/avatars/paul.png', '바울은 예수님을 만난 뒤 복음을 널리 전한 사도다. 여러 도시를 다니며 교회를 세우고 서신을 남겼다.', true, ARRAY['era_nt_apostolic', 'era_nt_post_apostolic']::text[]),
    ('john', '요한', '예수님의 열두 제자', 'assets/avatars/john.png', '요한은 예수님의 열두 제자 중 한 사람이다. 예수님의 사랑을 깊이 전했고 요한복음 전승과도 연결된다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic', 'era_nt_post_apostolic', 'era_nt_consummation']::text[]),
    ('peter', '베드로', '예수님의 열두 제자', 'assets/avatars/peter.png', '베드로는 예수님의 열두 제자 중 대표적인 인물로, 원래 갈릴리의 어부였다. 복음서와 초대교회에서 담대하게 복음을 전한다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic', 'era_nt_post_apostolic']::text[]),
    ('andrew', '안드레', '예수님의 열두 제자', 'assets/avatars/andrew.png', '안드레는 베드로의 형제이자 예수님의 제자였다. 먼저 예수님을 따르고 다른 사람을 데려오는 역할로 기억된다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('james_zebedee', '야고보(세베대의 아들)', '예수님의 열두 제자', 'assets/avatars/james_zebedee.png', '야고보(세베대의 아들)는 요한의 형제이자 예수님의 제자였다. 열정적인 제자 가운데 하나로 기억된다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('philip', '빌립', '예수님의 열두 제자', 'assets/avatars/philip.png', '빌립은 예수님의 제자 중 한 사람으로, 사람들을 예수님께 인도하는 모습으로 자주 등장한다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('moses', '모세', '출애굽의 지도자', 'assets/avatars/moses.png', '모세는 이스라엘 백성을 이집트에서 이끌어 낸 출애굽의 지도자다. 시내산에서 율법을 받아 백성에게 전했다.', true, ARRAY['era_exodus', 'era_nt_public_ministry']::text[]),
    ('matthew', '마태', '예수님의 열두 제자', 'assets/avatars/matthew.png', '마태는 세리 출신으로 예수님의 부르심을 받고 제자가 되었다. 전승에서는 마태복음과 연결된다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('bartholomew', '바돌로매', '예수님의 열두 제자', 'assets/avatars/bartholomew.png', '바돌로매는 예수님의 열두 제자 중 한 사람이다. 전승에서는 나다나엘과 연결해 보기도 한다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('james_alphaeus', '야고보(알패오의 아들)', '예수님의 열두 제자', 'assets/avatars/james_alphaeus.png', '야고보(알패오의 아들)는 예수님의 열두 제자 중 한 사람이다. 복음서에서는 조용하지만 끝까지 함께한 제자로 전해진다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('simon_zealot', '시몬(셀롯)', '예수님의 열두 제자', 'assets/avatars/simon_zealot.png', '시몬(셀롯)은 예수님의 열두 제자 중 한 사람이다. 이름에서 열심당과 관련된 배경을 짐작하게 한다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('thaddaeus', '다대오(유다)', '예수님의 열두 제자', 'assets/avatars/thaddaeus.png', '다대오(유다)는 예수님의 열두 제자 중 한 사람이다. 복음서에서는 유다라는 이름으로도 불린다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('thomas', '도마', '예수님의 열두 제자', 'assets/avatars/thomas.png', '도마는 예수님의 제자로, 부활하신 예수님을 확인하려 했던 모습으로 잘 알려져 있다. 이후에는 분명한 믿음의 고백을 남긴다.', true, ARRAY['era_nt_public_ministry', 'era_nt_apostolic']::text[]),
    ('david', '다윗', '언약을 받은 왕', 'assets/avatars/david.png', '다윗은 목동 출신으로 골리앗을 물리치고 이스라엘의 왕이 되었다. 시편과 깊이 연결되는 인물이다.', true, ARRAY['era_monarchy']::text[]),
    ('judas', '유다', '예수님을 배신한 제자', 'assets/avatars/judas.png', '가룟 유다는 예수님의 열두 제자 중 한 사람이었지만, 예수님을 넘겨준 인물로 기억된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('jacob', '야곱', '이스라엘의 조상', 'assets/avatars/jacob.png', '야곱은 이삭과 리브가의 아들로, 이스라엘 열두 지파의 조상이 되었다. 하나님과 씨름한 뒤 이스라엘이라는 이름을 받았다.', true, ARRAY['era_patriarch']::text[]),
    ('joshua', '여호수아', '가나안 정복 지도자', 'assets/avatars/joshua.png', '여호수아는 모세의 뒤를 이어 이스라엘 백성을 가나안으로 이끈 지도자다. 믿음과 순종으로 약속의 땅 정복을 이끌었다.', true, ARRAY['era_exodus']::text[]),
    ('abraham', '아브라함', '믿음의 조상', 'assets/avatars/abraham.png', '아브라함은 하나님의 부르심을 따라 고향을 떠난 믿음의 조상이다. 하나님은 그에게 자손과 땅에 대한 약속을 주셨다.', true, ARRAY['era_patriarch']::text[]),
    ('saul', '사울', '불순종한 초대 왕', 'assets/avatars/saul.png', '사울은 이스라엘의 첫 번째 왕이다. 처음에는 겸손했지만 점차 하나님께 불순종하며 비극적인 끝을 맞았다.', true, ARRAY['era_monarchy']::text[]),
    ('timothy', '디모데', '바울의 젊은 동역자', 'assets/avatars/timothy.png', '디모데는 바울의 젊은 동역자로, 여러 교회를 돌보며 신앙을 이어 간 인물이다.', true, ARRAY['era_nt_apostolic', 'era_nt_post_apostolic']::text[]),
    ('aaron', '아론', '이스라엘의 첫 대제사장', 'assets/avatars/aaron.png', '아론은 모세의 형으로, 출애굽 과정에서 모세를 도왔다. 이스라엘의 첫 대제사장으로도 중요한 위치를 차지한다.', true, ARRAY['era_exodus']::text[]),
    ('samuel', '사무엘', '사울과 다윗을 세운 선지자', 'assets/avatars/samuel.png', '사무엘은 사사이자 예언자로, 이스라엘이 왕정으로 넘어가는 중요한 시기를 이끈 인물이다.', true, ARRAY['era_judges', 'era_monarchy']::text[]),
    ('barnabas', '바나바', '초대교회 선교 동역자', 'assets/avatars/barnabas.png', '바나바는 초대교회에서 바울을 도와 선교에 함께한 동역자다. 사람을 격려하고 세우는 인물로 알려져 있다.', true, ARRAY['era_nt_apostolic', 'era_nt_post_apostolic']::text[]),
    ('joseph', '요셉', '꿈으로 이집트를 살린 총리', 'assets/avatars/joseph.png', '요셉은 야곱의 아들로, 형들에게 팔려 이집트에 갔지만 하나님의 인도 속에 총리가 되었다. 기근 속에서 가족을 살린 인물이다.', true, ARRAY['era_patriarch']::text[]),
    ('elijah', '엘리야', '아합과 맞선 불 선지자', 'assets/avatars/elijah.png', '엘리야는 북이스라엘에서 활동한 예언자다. 갈멜산 대결과 하나님의 불 응답 이야기로 잘 알려져 있다.', true, ARRAY['era_divided_kingdom', 'era_nt_public_ministry']::text[]),
    ('elisha', '엘리사', '엘리야를 이은 기적 선지자', 'assets/avatars/elisha.png', '엘리사는 엘리야의 뒤를 이어 활동한 예언자다. 여러 기적 이야기로 잘 알려져 있다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('pharaoh', '바로', '출애굽을 막은 이집트 왕', 'assets/avatars/pharaoh.png', '바로는 출애굽 이야기에서 이스라엘 백성을 억압한 이집트의 왕이다. 완고한 마음으로 하나님의 경고를 거듭 거부했다.', true, ARRAY['era_patriarch', 'era_exodus']::text[]),
    ('silas', '실라', '바울의 선교 동역자', 'assets/avatars/silas.png', '실라는 바울과 함께 여러 지역을 다니며 복음을 전한 초대교회 지도자다.', true, ARRAY['era_nt_apostolic', 'era_nt_post_apostolic']::text[]),
    ('ahab', '아합', '북이스라엘 7대 왕 바알 숭배', 'assets/avatars/ahab.png', '아합은 북이스라엘의 왕으로, 우상숭배와 악한 통치로 자주 언급된다. 엘리야 이야기에서 중요한 대적자로 등장한다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('mary', '마리아', '예수님의 어머니', 'assets/avatars/mary.png', '마리아는 예수님의 어머니로, 하나님의 부르심에 믿음으로 응답한 인물이다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('sarah', '사라', '약속의 어머니', 'assets/avatars/sarah.png', '사라는 아브라함의 아내이자 이삭의 어머니이다. 늦은 나이에 약속의 아들을 낳았다.', true, ARRAY['era_patriarch']::text[]),
    ('solomon', '솔로몬', '성전을 세운 지혜 왕', 'assets/avatars/solomon.png', '솔로몬은 다윗의 아들로, 지혜로 유명한 이스라엘의 왕이다. 예루살렘 성전을 세운 왕으로도 알려져 있다.', true, ARRAY['era_monarchy', 'era_divided_kingdom']::text[]),
    ('isaiah', '이사야', '히스기야를 도운 예루살렘 선지자', 'assets/avatars/isaiah.png', '이사야는 유다에서 활동한 예언자로, 심판과 회복 그리고 메시아에 대한 소망을 선포했다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('rachel', '라헬', '야곱의 아내', 'assets/avatars/rachel.png', '라헬은 야곱이 사랑한 아내이며 요셉과 베냐민의 어머니이다.', true, ARRAY['era_patriarch']::text[]),
    ('absalom', '압살롬', '다윗의 반역한 아들', 'assets/avatars/absalom.png', '압살롬은 성경에 등장하는 인물로, 대표적으로 ''암논과 다말: 압살롬의 분노'' 이야기와 연결된다.', true, ARRAY['era_monarchy']::text[]),
    ('daniel', '다니엘', '포로기 궁정 인물', 'assets/avatars/daniel.png', '다니엘은 바벨론 포로 시기에 하나님께 끝까지 충성한 인물이다. 지혜와 믿음으로 왕들 앞에서도 흔들리지 않았다.', true, ARRAY['era_divided_kingdom', 'era_exile_return']::text[]),
    ('esther', '에스더', '페르시아 왕후', 'assets/avatars/esther.png', '에스더는 페르시아 제국의 왕후가 되어 자기 민족을 위기에서 구한 인물이다. 지혜와 용기로 중요한 때를 붙든다.', true, ARRAY['era_exile_return']::text[]),
    ('isaac', '이삭', '약속의 아들', 'assets/avatars/isaac.png', '이삭은 아브라함과 사라에게 약속으로 주어진 아들이다. 야곱과 에서의 아버지이기도 하다.', true, ARRAY['era_patriarch']::text[]),
    ('james', '야고보', '초대교회 인물', 'assets/avatars/james.png', '야고보는 예수님의 제자 가운데 한 사람으로, 초대교회에서도 중요한 인물로 전해진다.', true, ARRAY['era_nt_apostolic', 'era_nt_post_apostolic']::text[]),
    ('jeremiah', '예레미야', '시드기야에게 경고한 눈물 선지자', 'assets/avatars/jeremiah.png', '예레미야는 예루살렘 멸망 전후에 활동한 예언자다. 눈물의 예언자로 불릴 만큼 아픈 시대에 말씀을 전했다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('john_the_baptist', '세례 요한', '광야의 세례자', 'assets/avatars/john_the_baptist.png', '세례 요한은 성경에 등장하는 인물로, 대표적으로 ''탄생 예고와 예수님의 탄생'' 이야기와 연결된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('leah', '레아', '야곱의 아내', 'assets/avatars/leah.png', '레아는 라반의 딸이자 야곱의 아내이다. 여러 아들의 어머니가 되어 이스라엘 가계에서 중요한 위치를 차지한다.', true, ARRAY['era_patriarch']::text[]),
    ('mordecai', '모르드개', '에스더의 조언자', 'assets/avatars/mordecai.png', '모르드개는 에스더를 돌보며 유다 민족을 지키기 위해 힘쓴 인물이다. 에스더 이야기에서 중요한 조언자 역할을 한다.', true, ARRAY['era_exile_return']::text[]),
    ('adam', '아담', '첫 사람', 'assets/avatars/adam.png', '아담은 하나님이 지으신 첫 사람이다. 하와와 함께 에덴동산 이야기의 중심에 선다.', true, ARRAY['era_primeval']::text[]),
    ('ahaziah_israel', '아하시야(북이스라엘)', '북이스라엘 8대 왕 우상 의지', 'assets/avatars/ahaziah_israel.png', '아하시야(북이스라엘)는 성경에 등장하는 인물로, 대표적으로 ''아합의 최후: 변장한 왕의 화살'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('aquila', '아굴라', '바울의 동역자', 'assets/avatars/aquila.png', '아굴라는 성경에 등장하는 인물로, 대표적으로 ''2차 전도 여행: 고린도 사역과 아굴라와 브리스길라'' 이야기와 연결된다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('bathsheba', '밧세바', '솔로몬의 어머니', 'assets/avatars/bathsheba.png', '밧세바는 성경에 등장하는 인물로, 대표적으로 ''다윗과 밧세바: 무너진 마음'' 이야기와 연결된다.', true, ARRAY['era_monarchy']::text[]),
    ('esau', '에서', '야곱의 형', 'assets/avatars/esau.png', '에서는 이삭의 아들이자 야곱의 형이다. 장자권을 가볍게 여긴 이야기로 잘 알려져 있다.', true, ARRAY['era_patriarch']::text[]),
    ('eve', '하와', '첫 여자', 'assets/avatars/eve.png', '하와는 하나님이 아담과 함께 살도록 주신 첫 여자이다. 에덴동산에서 뱀의 유혹을 받은 인물로 등장한다.', true, ARRAY['era_primeval']::text[]),
    ('herod', '헤롯', '유대 지역 왕', 'assets/avatars/herod.png', '헤롯은 성경에 등장하는 인물로, 대표적으로 ''탄생 예고와 예수님의 탄생'' 이야기와 연결된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('jehoshaphat', '여호사밧', '남유다 4대 왕 말씀 개혁', 'assets/avatars/jehoshaphat.png', '여호사밧은 성경에 등장하는 인물로, 대표적으로 ''미가야: 거짓 예언 앞의 진실'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('jeroboam', '여로보암', '북이스라엘 1대 왕 금송아지 죄', 'assets/avatars/jeroboam.png', '여로보암은 성경에 등장하는 인물로, 대표적으로 ''왕국의 균열: 찢어진 옷'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('jezebel', '이세벨', '아합을 부추긴 시돈 왕비', 'assets/avatars/jezebel.png', '이세벨은 시돈 왕가 출신으로 아합과 함께 북이스라엘에 바알 숭배를 깊이 들여온 왕비다. 나봇의 포도원 사건에서도 악한 계략을 꾸민다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('joash_judah', '요아스(남유다)', '남유다 8대 왕 성전 보수', 'assets/avatars/joash_judah.png', '요아스(남유다)는 성경에 등장하는 인물로, 대표적으로 ''아달랴와 요아스: 숨겨진 왕'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('jonathan', '요나단', '사울의 아들', 'assets/avatars/jonathan.png', '요나단은 성경에 등장하는 인물로, 대표적으로 ''사울의 시기: 다윗의 도망 시작'' 이야기와 연결된다.', true, ARRAY['era_monarchy']::text[]),
    ('judah', '유다', '유다 지파의 조상', 'assets/avatars/judah.png', '유다는 야곱의 아들 가운데 한 사람으로, 훗날 메시아 계보와 연결되는 지파의 조상이 되었다.', true, ARRAY['era_patriarch']::text[]),
    ('laban', '라반', '야곱의 외삼촌', 'assets/avatars/laban.png', '라반은 리브가의 오빠이자 야곱의 외삼촌이다. 야곱이 그의 집에서 오랫동안 일하며 레아와 라헬을 아내로 맞게 된다.', true, ARRAY['era_patriarch']::text[]),
    ('lot', '롯', '소돔에서 건짐받은 조카', 'assets/avatars/lot.png', '롯은 아브라함의 조카로, 소돔과 고모라 이야기에서 잘 알려진다.', true, ARRAY['era_patriarch']::text[]),
    ('mary_magdalene', '막달라 마리아', '예수님을 따른 여인', 'assets/avatars/mary_magdalene.png', '막달라 마리아는 성경에 등장하는 인물로, 대표적으로 ''십자가'' 이야기와 연결된다.', true, ARRAY['era_nt_public_ministry']::text[]),
    ('naomi', '나오미', '룻의 시어머니', 'assets/avatars/naomi.png', '나오미는 룻의 시어머니로, 깊은 상실 속에서도 하나님의 돌보심을 다시 경험한다.', true, ARRAY['era_judges']::text[]),
    ('nehemiah', '느헤미야', '예루살렘 성벽 재건자', 'assets/avatars/nehemiah.png', '느헤미야는 페르시아 궁정에서 일하다가 예루살렘 성벽 재건을 이끈 지도자다.', true, ARRAY['era_exile_return']::text[]),
    ('philip_evangelist', '전도자 빌립', '초대교회 인물', 'assets/avatars/philip_evangelist.png', '전도자 빌립은 성경에 등장하는 인물로, 대표적으로 ''예루살렘 교회 박해와 사마리아 전도'' 이야기와 연결된다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('priscilla', '브리스길라', '바울의 동역자', 'assets/avatars/priscilla.png', '브리스길라는 성경에 등장하는 인물로, 대표적으로 ''2차 전도 여행: 고린도 사역과 아굴라와 브리스길라'' 이야기와 연결된다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('rehoboam', '르호보암', '남유다 1대 왕 왕국 분열', 'assets/avatars/rehoboam.png', '르호보암은 성경에 등장하는 인물로, 대표적으로 ''왕국의 균열: 찢어진 옷'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('reuben', '르우벤', '야곱의 맏아들', 'assets/avatars/reuben.png', '르우벤은 야곱의 맏아들이다. 장자의 위치를 가졌지만 그 책임을 끝까지 지키지는 못했다.', true, ARRAY['era_patriarch']::text[]),
    ('ruth', '룻', '모압 출신 믿음의 여인', 'assets/avatars/ruth.png', '룻은 모압 여인이었지만 나오미를 따라 이스라엘로 와 믿음의 길을 택했다. 보아스와의 결혼을 통해 다윗의 계보에 들어간다.', true, ARRAY['era_judges']::text[]),
    ('zedekiah', '시드기야', '남유다 20대 마지막 왕', 'assets/avatars/zedekiah.png', '시드기야는 성경에 등장하는 인물로, 대표적으로 ''여호야긴의 포로: 성전 금 기구가 깨어지다'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('zerubbabel', '스룹바벨', '성전 재건 총독', 'assets/avatars/zerubbabel.png', '스룹바벨은 성경에 등장하는 인물로, 대표적으로 ''귀환과 성전 기초: 시작과 중단'' 이야기와 연결된다.', true, ARRAY['era_exile_return']::text[]),
    ('abednego', '아벳느고', '포로 귀환 시대 인물', 'assets/avatars/abednego.png', '아벳느고는 성경에 등장하는 인물로, 대표적으로 ''다니엘: 뜻을 정하다'' 이야기와 연결된다.', true, ARRAY['era_exile_return']::text[]),
    ('agrippa', '아그립바', '바울을 심문한 왕', 'assets/avatars/agrippa.png', '아그립바는 성경에 등장하는 인물로, 대표적으로 ''베스도 앞 재판과 가이사 상소'' 이야기와 연결된다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('ahaz', '아하스', '남유다 12대 왕 앗수르 의지', 'assets/avatars/ahaz.png', '아하스는 성경에 등장하는 인물로, 대표적으로 ''아하스의 우상과 다메섹 제단'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('ahaziah_judah', '아하시야(남유다)', '남유다 6대 왕 아합 집 동맹', 'assets/avatars/ahaziah_judah.png', '아하시야(남유다)는 성경에 등장하는 인물로, 대표적으로 ''유다 아하시야: 길르앗 라못의 상처'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('ahijah', '아히야', '여로보암에게 경고한 실로 선지자', 'assets/avatars/ahijah.png', '아히야는 실로 출신 선지자로, 여로보암에게 찢어진 옷의 표징을 보이고 그의 집에 임할 하나님의 경고를 전했다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('amaziah_judah', '아마샤', '남유다 9대 왕 에돔 승리', 'assets/avatars/amaziah_judah.png', '아마샤는 성경에 등장하는 인물로, 대표적으로 ''아마샤와 북이스라엘 요아스: 교만한 도전'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('benjamin', '베냐민', '야곱의 막내아들', 'assets/avatars/benjamin.png', '베냐민은 야곱과 라헬 사이에서 태어난 막내아들이다. 요셉 이야기에서 형제들의 변화와 함께 중요한 역할을 한다.', true, ARRAY['era_patriarch']::text[]),
    ('boaz', '보아스', '룻을 보호한 기업 무를 자', 'assets/avatars/boaz.png', '보아스는 룻을 선대하고 보호한 친족 기업 무를 자이다. 룻과 결혼해 다윗 가문의 조상이 된다.', true, ARRAY['era_judges']::text[]),
    ('eli', '엘리', '실로의 제사장', 'assets/avatars/eli.png', '엘리는 성경에 등장하는 인물로, 대표적으로 ''사무엘의 탄생: 한나의 눈물'' 이야기와 연결된다.', true, ARRAY['era_judges']::text[]),
    ('ezekiel', '에스겔', '포로 백성에게 환상 보인 선지자', 'assets/avatars/ezekiel.png', '에스겔은 바벨론 포로 시기에 활동한 예언자다. 상징 행동과 환상을 통해 하나님의 말씀을 전했다.', true, ARRAY['era_divided_kingdom', 'era_exile_return']::text[]),
    ('ezra', '에스라', '율법을 가르친 학자', 'assets/avatars/ezra.png', '에스라는 포로 귀환 이후 백성에게 율법을 가르치고 공동체를 바로 세운 학자 겸 제사장이다.', true, ARRAY['era_exile_return']::text[]),
    ('festus', '베스도', '로마 총독', 'assets/avatars/festus.png', '베스도는 성경에 등장하는 인물로, 대표적으로 ''베스도 앞 재판과 가이사 상소'' 이야기와 연결된다.', true, ARRAY['era_nt_apostolic']::text[]),
    ('gideon', '기드온', '300명으로 미디안 이긴 사사', 'assets/avatars/gideon.png', '기드온은 미디안의 압제 아래 있던 이스라엘을 구하도록 부름받은 사사이다. 작은 수의 군사로 하나님의 구원을 경험했다.', true, ARRAY['era_judges']::text[]),
    ('hagar', '하갈', '이스마엘의 어머니', 'assets/avatars/hagar.png', '하갈은 사라의 여종이었고 아브라함을 통해 이스마엘을 낳았다. 광야에서 하나님이 자신을 돌보심을 경험한다.', true, ARRAY['era_patriarch']::text[]),
    ('haggai', '학개', '스룹바벨을 격려한 성전 선지자', 'assets/avatars/haggai.png', '학개는 성경에 등장하는 인물로, 대표적으로 ''학개의 말씀: 스룹바벨을 택하다'' 이야기와 연결된다.', true, ARRAY['era_exile_return']::text[]),
    ('haman', '하만', '유다인을 대적한 고관', 'assets/avatars/haman.png', '하만은 페르시아 제국에서 유다인을 없애려 한 악한 고관이다. 에스더 이야기의 주요 대적자로 나온다.', true, ARRAY['era_exile_return']::text[]),
    ('hezekiah', '히스기야', '남유다 13대 왕 기도와 개혁', 'assets/avatars/hezekiah.png', '히스기야는 유다의 왕으로, 하나님을 의지하며 종교 개혁을 이루려 했던 인물이다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('hoshea_king', '호세아 왕', '북이스라엘 19대 마지막 왕', 'assets/avatars/hoshea_king.png', '호세아 왕은 성경에 등장하는 인물로, 대표적으로 ''북이스라엘 말기 왕들: 반역의 연쇄'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('ishmael', '이스마엘', '아브라함의 아들', 'assets/avatars/ishmael.png', '이스마엘은 아브라함과 하갈 사이에서 태어난 아들이다. 광야로 나가게 되지만 하나님이 그와 그의 어머니를 돌보셨다.', true, ARRAY['era_patriarch']::text[]),
    ('jehoahaz_israel', '여호아하스(북이스라엘)', '북이스라엘 11대 왕 아람 압박', 'assets/avatars/jehoahaz_israel.png', '여호아하스(북이스라엘)는 성경에 등장하는 인물로, 대표적으로 ''예후의 열심과 한계: 바알 신전과 금송아지'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('jehoash_israel', '요아스(북이스라엘)', '북이스라엘 12대 왕 엘리사 문병', 'assets/avatars/jehoash_israel.png', '요아스(북이스라엘)는 성경에 등장하는 인물로, 대표적으로 ''여호아하스와 요아스: 엘리사의 마지막 화살'' 이야기와 연결된다.', true, ARRAY['era_divided_kingdom']::text[]),
    ('jehoiada', '여호야다', '요아스를 보호한 성전 제사장', 'assets/avatars/jehoiada.png', '여호야다는 예루살렘 성전의 제사장으로, 아달랴 시대에 어린 요아스를 보호하고 언약을 새롭게 세워 다윗 왕조를 이어 가게 한 인물이다.', true, ARRAY['era_divided_kingdom']::text[]),
