)
insert into characters (code, name, tagline, avatar_url, description, is_active, era_codes)
select code, name, tagline, avatar_url, description, is_active, era_codes from seed_persons
on conflict (code) do update set
  name = excluded.name,
  tagline = coalesce(excluded.tagline, characters.tagline),
  avatar_url = excluded.avatar_url,
  description = coalesce(excluded.description, characters.description),
  era_codes = excluded.era_codes,
  is_active = case
    when excluded.code in ('elizabeth', 'gabriel', 'god') then false
    when excluded.is_active then true
    else characters.is_active
  end
;

commit;
